function ProviderIcon(props: { provider: SocialProvider }) {
  if (props.provider === "github") return <GitHubIcon class="size-4" />
  if (props.provider === "google") return <GoogleIcon class="size-4" />

  return <span aria-hidden>{getProviderName(props.provider).slice(0, 1)}</span>
}

export function ProviderButton(props: ProviderButtonProps) {
  const auth = useAuth()
  const [isPending, setIsPending] = createSignal(false)
  const display = () => props.display ?? "full"
  const providerName = () => getProviderName(props.provider)
  const label = () =>
    auth.localization.auth.continueWith.replace("{{provider}}", providerName())
  const signInSocial = async () => {
    if (isPending()) return

    setIsPending(true)

    try {
      await auth.authClient.signIn.social(
        resolveSocialAuthParams({
          provider: props.provider,
          basePaths: auth.basePaths,
          baseURL: auth.baseURL,
          redirectTo: auth.redirectTo,
          view: props.view ?? "signIn",
          viewPaths: auth.viewPaths
        }) as Parameters<typeof auth.authClient.signIn.social>[0]
      )
    } finally {
      setIsPending(false)
    }
  }

  return (
    <Button
      aria-label={providerName()}
      class={props.class}
      disabled={isPending()}
      onClick={signInSocial}
      type="button"
      variant={props.variant ?? "outline"}
    >
      {isPending() ? <Spinner /> : <ProviderIcon provider={props.provider} />}
      {isPending()
        ? null
        : display() === "full"
          ? label()
          : display() === "name"
            ? providerName()
            : null}
    </Button>
  )
}

import { useAuth } from "@better-auth-ui/solid"
import { For } from "solid-js"
import { cn } from "@/lib/utils"
import { ProviderButton } from "./provider-button"
import type { SocialAuthView } from "./sign-in-path"

export type SocialLayout = "auto" | "grid" | "horizontal" | "vertical"

export type ProviderButtonsProps = {
  socialLayout?: SocialLayout
  view?: SocialAuthView
}

export function ProviderButtons(props: ProviderButtonsProps) {
  const auth = useAuth()
  const resolvedSocialLayout = () => {
    const socialLayout = props.socialLayout ?? "auto"
    if (socialLayout !== "auto") return socialLayout

    return auth.socialProviders?.length && auth.socialProviders.length >= 4
      ? "horizontal"
      : "vertical"
  }

  return (
    <div
      class={cn(
        "gap-3",
        resolvedSocialLayout() === "grid" && "grid grid-cols-2",
        resolvedSocialLayout() === "vertical" && "flex flex-col",
        resolvedSocialLayout() === "horizontal" && "flex flex-row flex-wrap"
      )}
    >
      <For each={auth.socialProviders ?? []}>
        {(provider) => (
          <ProviderButton
            class={cn(resolvedSocialLayout() === "horizontal" && "flex-1")}
            display={
              resolvedSocialLayout() === "vertical"
                ? "full"
                : resolvedSocialLayout() === "grid"
                  ? "name"
                  : "icon"
            }
            provider={provider}
            view={props.view}
          />
        )}
      </For>
    </div>
  )
}

import { type ClassValue, clsx } from "clsx"
import { twMerge } from "tailwind-merge"

export const cn = (...inputs: ClassValue[]) => twMerge(clsx(inputs))
